#!/usr/bin/env python3
"""worldbook_claude build - Sources & Methodology: bundle per-layer provenance and
render the Sources panel organized BY LAYER (metric/unit/color-meaning/source/method/
limitations/confidence) + a Borders & disputed-territories section. Idempotent, ASCII."""
import sys
INP=sys.argv[1] if len(sys.argv)>1 else "index.html"
OUT=sys.argv[2] if len(sys.argv)>2 else "index.html"
text=open(INP,encoding="utf-8").read()
NEW=r'''/* ===== Sources & Methodology (bundled provenance, by layer) ================== */
const LAYER_PROV={"religion":{"label":"Religion by branch","metric":"Share of each country's population identifying with major religious groups (Christian, Muslim, Hindu, Buddhist, Jewish, other, unaffiliated).","unit":"category / percent of population","higherIs":"neutral","colorMeaning":"Color encodes the dominant or plurality religious group in each country.","primarySource":{"org":"Pew Research Center","datasetTitle":"How the Global Religious Landscape Changed from 2010 to 2020","url":"https://www.pewresearch.org/religion/2025/06/09/how-the-global-religious-landscape-changed-from-2010-to-2020/","year":"2025 (reference year 2020)"},"additionalSources":[{"org":"Association of Religion Data Archives (ARDA) / World Religion Database","datasetTitle":"World Religion Database","url":"https://www.thearda.com/"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"periodic (roughly once per decade)","methodology":"Religious composition estimated for seven broad categories from more than 2,700 sources including national censuses, demographic surveys, and population registers.","limitations":"Resolves only seven broad categories, not denominational branches (e.g. Sunni/Shia, Catholic/Protestant), and self-identification quality varies widely by country.","confidence":"high"},"govtype":{"label":"Government type","metric":"Descriptive classification of each country's system of government (e.g. federal presidential republic, parliamentary constitutional monarchy).","unit":"category","higherIs":"neutral","colorMeaning":"Color encodes the structural government-type category assigned to each country.","primarySource":{"org":"U.S. Central Intelligence Agency","datasetTitle":"The World Factbook \u2014 Government type field","url":"https://www.cia.gov/the-world-factbook/field/government-type/","year":"2026 (last state ~Jan 2026)"},"additionalSources":[{"org":"World Factbook Archive","datasetTitle":"Archived World Factbook snapshots","url":"https://worldfactbookarchive.org/"}],"dataKind":"curated","provenance":"primary","updateFrequency":"static/historical (CIA discontinued the Factbook on 4 Feb 2026)","methodology":"Editorial classification by CIA analysts assigning each entity a descriptive label for its system of government.","limitations":"Now frozen and unmaintained as of Feb 2026; labels are descriptive and non-standardized rather than a coded academic typology.","confidence":"medium"},"regime":{"label":"Regime type","metric":"Classification of each country along the democracy\u2013autocracy spectrum (e.g. liberal democracy, electoral democracy, electoral autocracy, closed autocracy).","unit":"category / index score","higherIs":"context","colorMeaning":"Color encodes regime category, typically from more democratic to more autocratic.","primarySource":{"org":"V-Dem Institute, University of Gothenburg","datasetTitle":"V-Dem Dataset v16 / Democracy Report 2026","url":"https://www.v-dem.net/data/the-v-dem-dataset/","year":"2026 (scores through 2025)"},"additionalSources":[{"org":"Economist Intelligence Unit","datasetTitle":"Democracy Index 2025","url":"https://www.eiu.com/n/campaigns/democracy-index-2025/"},{"org":"Freedom House","datasetTitle":"Freedom in the World 2026","url":"https://freedomhouse.org/report/freedom-world"},{"org":"Center for Systemic Peace","datasetTitle":"Polity5 (discontinued, ends 2018)","url":"https://www.systemicpeace.org/polityproject.html"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"annual","methodology":"V-Dem aggregates thousands of expert codings across hundreds of indicators into democracy indices and a Regimes-of-the-World typology.","limitations":"Relies on subjective expert judgments aggregated via measurement models, introducing rater uncertainty; Polity5 is frozen at 2018 and should not be treated as current.","confidence":"high"},"language":{"label":"Language family","metric":"Dominant language and its genealogical language family for each country.","unit":"category","higherIs":"neutral","colorMeaning":"Color encodes the language family of the country's dominant or official language.","primarySource":{"org":"Max Planck Institute for Evolutionary Anthropology","datasetTitle":"Glottolog 5.3","url":"https://glottolog.org/","year":"2025"},"additionalSources":[{"org":"SIL International","datasetTitle":"Ethnologue: Languages of the World, 28th edition","url":"https://www.ethnologue.com/"},{"org":"Max Planck Institute / Zenodo","datasetTitle":"World Atlas of Language Structures (WALS)","url":"https://wals.info/"}],"dataKind":"curated","provenance":"primary","updateFrequency":"periodic","methodology":"Glottolog provides a rigorously curated genealogical classification of the world's languages keyed to Glottocodes; dominant language per country is assigned editorially.","limitations":"Language-vs-dialect splitting decisions are contested among linguists, and a single 'dominant language per country' obscures multilingual states.","confidence":"high"},"popdensity":{"label":"Population density","metric":"Mid-year population divided by land area, people per square kilometer.","unit":"people per sq km","higherIs":"neutral","colorMeaning":"Color encodes population density, from sparse to dense.","primarySource":{"org":"World Bank","datasetTitle":"World Development Indicators \u2014 Population density (EN.POP.DNST)","url":"https://data.worldbank.org/indicator/EN.POP.DNST","year":"2023"},"additionalSources":[{"org":"UN DESA Population Division","datasetTitle":"World Population Prospects 2024","url":"https://population.un.org/wpp/"}],"dataKind":"estimated","provenance":"secondary","updateFrequency":"annual","methodology":"Mid-year total population (UN WPP) divided by land area in square kilometers (FAO), excluding inland water bodies.","limitations":"A national average that masks enormous internal variation (deserts vs. cities) and is sensitive to how land area is defined.","confidence":"high"},"gdppc":{"label":"GDP per capita","metric":"Gross domestic product divided by mid-year population, in purchasing-power-parity international dollars.","unit":"international $ (PPP) per person","higherIs":"good","colorMeaning":"Color encodes GDP per capita, from lower to higher income.","primarySource":{"org":"World Bank","datasetTitle":"World Development Indicators \u2014 GDP per capita, PPP (NY.GDP.PCAP.PP.CD)","url":"https://data.worldbank.org/indicator/NY.GDP.PCAP.PP.CD","year":"2024"},"additionalSources":[{"org":"International Monetary Fund","datasetTitle":"World Economic Outlook Database (April 2026)","url":"https://www.imf.org/en/publications/weo/weo-database/2026/april"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"annual (database refreshed quarterly)","methodology":"GDP divided by mid-year population, converted at purchasing-power-parity factors from the International Comparison Program to equalize price levels.","limitations":"PPP conversion factors depend on periodic ICP price surveys and are extrapolated between benchmark years, carrying meaningful estimation uncertainty.","confidence":"high"},"lifeexp":{"label":"Life expectancy","metric":"Number of years a newborn would live if current mortality patterns held constant throughout life.","unit":"years","higherIs":"good","colorMeaning":"Color encodes life expectancy at birth, from lower to higher.","primarySource":{"org":"World Bank","datasetTitle":"World Development Indicators \u2014 Life expectancy at birth, total (SP.DYN.LE00.IN)","url":"https://data.worldbank.org/indicator/SP.DYN.LE00.IN","year":"2023"},"additionalSources":[{"org":"UN DESA Population Division","datasetTitle":"World Population Prospects 2024","url":"https://population.un.org/wpp/"},{"org":"World Health Organization","datasetTitle":"Global Health Observatory \u2014 Life expectancy","url":"https://www.who.int/data/gho"}],"dataKind":"estimated","provenance":"secondary","updateFrequency":"annual","methodology":"Period (synthetic-cohort) life expectancy compiled from UN World Population Prospects and national statistical offices.","limitations":"Assumes today's mortality stays fixed, so it does not predict any actual person's lifespan, and figures lag real time by about two years.","confidence":"high"},"internet":{"label":"Internet use","metric":"Share of individuals using the Internet as a percentage of population.","unit":"percent of population","higherIs":"good","colorMeaning":"Color encodes the percentage of the population online, from low to high.","primarySource":{"org":"International Telecommunication Union","datasetTitle":"Measuring Digital Development: Facts and Figures 2025","url":"https://www.itu.int/itu-d/reports/statistics/facts-figures-2025/","year":"2025 estimates"},"additionalSources":[{"org":"World Bank","datasetTitle":"WDI \u2014 Individuals using the Internet (IT.NET.USER.ZS)","url":"https://data.worldbank.org/indicator/IT.NET.USER.ZS"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"annual","methodology":"Compiled from national household surveys and administrative data reported to ITU, with modelling to fill gaps and produce comparable global figures.","limitations":"Definitions of 'Internet use' and survey recency vary by country, so many developing-country figures are ITU estimates rather than directly measured.","confidence":"high"},"govdebt":{"label":"Government debt (% of GDP)","metric":"General government gross debt as a share of GDP.","unit":"percent of GDP","higherIs":"context","colorMeaning":"Color encodes the gross government debt-to-GDP ratio, from low to high.","primarySource":{"org":"International Monetary Fund","datasetTitle":"World Economic Outlook Database \u2014 General government gross debt, % of GDP (GGXWDG_NGDP)","url":"https://www.imf.org/external/datamapper/GGXWDG_NGDP@WEO/WEOWORLD","year":"2025 (WEO April 2026)"},"additionalSources":[{"org":"International Monetary Fund","datasetTitle":"Fiscal Monitor (April 2026)","url":"https://www.imf.org/en/publications/fm"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"biannual (April and October)","methodology":"Total gross debt liabilities of the general government sector as a share of GDP, compiled from country authorities and harmonized to a common framework.","limitations":"General-government coverage and gross-vs-net treatment differ across countries, and out-year figures are projections subject to large revision.","confidence":"high"},"co2pc":{"label":"CO2 per capita","metric":"Territorial (production-based) fossil-fuel and industry CO2 emissions divided by population, tonnes per person per year.","unit":"tonnes CO2 per capita","higherIs":"bad","colorMeaning":"Color encodes per-capita CO2 emissions, from low to high.","primarySource":{"org":"Global Carbon Project","datasetTitle":"Global Carbon Budget 2025","url":"https://globalcarbonbudget.org/","year":"2025 (data through 2024)"},"additionalSources":[{"org":"Our World in Data","datasetTitle":"CO\u2082 emissions per capita","url":"https://ourworldindata.org/grapher/co-emissions-per-capita"},{"org":"EC Joint Research Centre","datasetTitle":"EDGAR \u2014 Emissions Database for Global Atmospheric Research","url":"https://edgar.jrc.ec.europa.eu/"}],"dataKind":"estimated","provenance":"secondary","updateFrequency":"annual","methodology":"Territorial fossil-fuel and industry CO2 emissions estimated from energy and cement statistics, divided by population.","limitations":"Production-based figures exclude trade-embodied (consumption) emissions and land-use change, understating the footprint of high-import economies.","confidence":"high"},"climate":{"label":"Koppen climate","metric":"Koppen-Geiger climate classification of each location based on temperature and precipitation regimes.","unit":"category","higherIs":"neutral","colorMeaning":"Color encodes the Koppen-Geiger climate zone (e.g. tropical, arid, temperate, continental, polar).","primarySource":{"org":"Beck et al. (GloH2O), Nature Scientific Data","datasetTitle":"High-resolution (1 km) Koppen-Geiger maps, Version 2 (2023)","url":"https://www.gloh2o.org/koppen/","year":"2023 (1991\u20132020 climatology)"},"additionalSources":[{"org":"Beck et al., Nature Scientific Data","datasetTitle":"Present and future Koppen-Geiger climate classification maps at 1-km resolution (2018)","url":"https://www.nature.com/articles/sdata2018214"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"static/historical (versioned releases: 2018, 2023)","methodology":"Koppen-Geiger classes assigned at ~1 km resolution from topographically-corrected, observation-based temperature and precipitation climatologies.","limitations":"A rule-based discretization of continuous climate, so class boundaries are artificial and confidence is lower in data-sparse regions.","confidence":"high"},"lgbt":{"label":"LGBTQ+ legal status","metric":"Legal status of LGBTQ+ people, from criminalization of same-sex acts through anti-discrimination protections and marriage equality.","unit":"category","higherIs":"good","colorMeaning":"Color encodes the level of legal protection vs. criminalization for LGBTQ+ people.","primarySource":{"org":"ILGA World","datasetTitle":"Laws on Us: A Global Overview of Legal Progress and Backtracking on SOGIESC","url":"https://ilga.org/laws-on-us-report/","year":"2024 (1st edition)"},"additionalSources":[{"org":"ILGA World","datasetTitle":"Criminalisation maps / sexual orientation laws maps","url":"https://database.ilga.org/"}],"dataKind":"curated","provenance":"primary","updateFrequency":"periodic (report); maps updated as laws change","methodology":"Surveys laws across 193 UN member states in multiple legal categories (criminalization, anti-discrimination, recognition, marriage, gender recognition).","limitations":"Captures laws on the books rather than enforcement or lived reality, and snapshots lag real-time legal change between editions.","confidence":"high"},"under5mort":{"label":"Under-5 mortality","metric":"Probability per 1,000 live births that a child dies before reaching age five.","unit":"deaths per 1,000 live births","higherIs":"bad","colorMeaning":"Color encodes the under-5 mortality rate, from low to high.","primarySource":{"org":"UN Inter-agency Group for Child Mortality Estimation (UNICEF, WHO, World Bank, UN DESA)","datasetTitle":"Levels & Trends in Child Mortality: Report 2024","url":"https://childmortality.org/","year":"2023 (Report 2024)"},"additionalSources":[{"org":"UNICEF Data","datasetTitle":"Levels and Trends in Child Mortality","url":"https://data.unicef.org/resources/levels-and-trends-in-child-mortality-2024/"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"annual","methodology":"Estimated via a Bayesian B-spline model fitting surveys, censuses, and vital registration data.","limitations":"For countries lacking strong vital registration, estimates rely on modeled survey data with wide uncertainty intervals.","confidence":"high"},"matmort":{"label":"Maternal mortality","metric":"Maternal deaths per 100,000 live births.","unit":"deaths per 100,000 live births","higherIs":"bad","colorMeaning":"Color encodes the maternal mortality ratio, from low to high.","primarySource":{"org":"UN Maternal Mortality Estimation Inter-Agency Group (WHO, UNICEF, UNFPA, World Bank, UN DESA)","datasetTitle":"Trends in Maternal Mortality 2000 to 2023","url":"https://www.who.int/publications/i/item/9789240108462","year":"2023"},"additionalSources":[{"org":"World Bank","datasetTitle":"WDI \u2014 Maternal mortality ratio (SH.STA.MMRT)","url":"https://data.worldbank.org/indicator/SH.STA.MMRT"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"periodic (roughly every 2\u20133 years)","methodology":"Maternal deaths per 100,000 live births estimated with a Bayesian model combining vital registration, surveys, and censuses.","limitations":"Maternal deaths are frequently misclassified or underreported, so most country figures are modeled with broad uncertainty ranges.","confidence":"high"},"physicians":{"label":"Physicians per 1,000","metric":"Number of generalist and specialist medical doctors per 1,000 population.","unit":"physicians per 1,000 people","higherIs":"good","colorMeaning":"Color encodes physician density, from low to high.","primarySource":{"org":"World Health Organization","datasetTitle":"Global Health Workforce Statistics / National Health Workforce Accounts \u2014 Medical doctors","url":"https://www.who.int/data/gho/data/indicators/indicator-details/GHO/medical-doctors-(per-10-000-population)","year":"latest available, mostly 2021\u20132023"},"additionalSources":[{"org":"World Bank","datasetTitle":"WDI \u2014 Physicians per 1,000 people (SH.MED.PHYS.ZS)","url":"https://data.worldbank.org/indicator/SH.MED.PHYS.ZS"}],"dataKind":"measured","provenance":"secondary","updateFrequency":"as countries report (not all annually)","methodology":"Counts generalist and specialist medical practitioners per population, reported by national authorities via the NHWA platform.","limitations":"Country data years differ widely (latest-available is used), and figures count registered/licensed doctors rather than those actively practicing.","confidence":"medium"},"healthspend":{"label":"Health spending (% GDP)","metric":"Current health expenditure (public, private, and external) as a share of GDP.","unit":"percent of GDP","higherIs":"context","colorMeaning":"Color encodes total health spending as a share of GDP, from low to high.","primarySource":{"org":"World Health Organization","datasetTitle":"Global Health Expenditure Database \u2014 Current health expenditure as % of GDP","url":"https://apps.who.int/nha/database/","year":"2023"},"additionalSources":[{"org":"World Bank","datasetTitle":"WDI \u2014 Current health expenditure (% of GDP) (SH.XPD.CHEX.GD.ZS)","url":"https://data.worldbank.org/indicator/SH.XPD.CHEX.GD.ZS"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"annual","methodology":"Sums all current health spending as a share of GDP under the System of Health Accounts (SHA 2011) framework.","limitations":"Cross-country comparability is limited by differing accounting practices, and donor flows are hard to capture in low-income countries.","confidence":"high"},"hiv":{"label":"HIV prevalence","metric":"Share of the population aged 15\u201349 living with HIV.","unit":"percent of adults aged 15\u201349","higherIs":"bad","colorMeaning":"Color encodes adult HIV prevalence, from low to high.","primarySource":{"org":"UNAIDS","datasetTitle":"UNAIDS 2025 epidemiological estimates / AIDSinfo","url":"https://aidsinfo.unaids.org/","year":"2024"},"additionalSources":[{"org":"World Bank","datasetTitle":"WDI \u2014 Prevalence of HIV, ages 15-49 (SH.DYN.AIDS.ZS)","url":"https://data.worldbank.org/indicator/SH.DYN.AIDS.ZS"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"annual","methodology":"Share of adults aged 15\u201349 living with HIV, modeled with the Spectrum/EPP tools using surveillance, survey, and programme data.","limitations":"Estimates carry wide uncertainty bounds, especially in concentrated epidemics where surveillance among key populations is incomplete.","confidence":"high"},"water":{"label":"Safe drinking water","metric":"Share of population using safely managed drinking water services (improved source, on premises, available when needed, free of contamination).","unit":"percent of population","higherIs":"good","colorMeaning":"Color encodes access to safely managed drinking water, from low to high.","primarySource":{"org":"WHO/UNICEF Joint Monitoring Programme","datasetTitle":"Progress on Household Drinking Water, Sanitation and Hygiene 2000\u20132024","url":"https://washdata.org/","year":"2024"},"additionalSources":[{"org":"UNICEF Data","datasetTitle":"JMP report 2025","url":"https://data.unicef.org/resources/jmp-report-2025/"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"periodic (roughly every two years)","methodology":"Share of population using an improved water source on premises, available when needed and free of contamination, modeled from surveys, censuses, and administrative data.","limitations":"Many countries lack water-quality and accessibility data, so the 'safely managed' tier must be estimated and is unavailable for a substantial share of the population.","confidence":"high"},"sanitation":{"label":"Sanitation access","metric":"Share of population using safely managed sanitation services (improved, non-shared facility with safe disposal or treatment of excreta).","unit":"percent of population","higherIs":"good","colorMeaning":"Color encodes access to safely managed sanitation, from low to high.","primarySource":{"org":"WHO/UNICEF Joint Monitoring Programme","datasetTitle":"Progress on Household Drinking Water, Sanitation and Hygiene 2000\u20132024","url":"https://washdata.org/","year":"2024"},"additionalSources":[{"org":"UNICEF Data","datasetTitle":"JMP report 2025","url":"https://data.unicef.org/resources/jmp-report-2025/"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"periodic (roughly every two years)","methodology":"Share of population using an improved, non-shared facility where excreta are safely disposed in situ or transported and treated offsite.","limitations":"Data on the final disposal or treatment of excreta are sparse in many countries, so safely managed estimates are modeled and often unavailable nationally.","confidence":"high"},"braindrain":{"label":"Medical brain drain","metric":"Origin-to-destination movement of foreign-trained doctors and nurses working in destination (mainly OECD) countries.","unit":"category / count of health professionals","higherIs":"context","colorMeaning":"Path color/weight encodes the volume of health professionals trained in an origin country and working abroad.","primarySource":{"org":"OECD","datasetTitle":"International Migration Outlook 2025 \u2014 International migration of health professionals to OECD countries","url":"https://www.oecd.org/en/publications/international-migration-outlook-2025_ae26c893-en.html","year":"2021\u20132023"},"additionalSources":[{"org":"World Health Organization","datasetTitle":"Health Workforce Support and Safeguards List 2023 / Global Code of Practice on International Recruitment","url":"https://www.who.int/publications/i/item/9789240069787"}],"dataKind":"curated","provenance":"secondary","updateFrequency":"periodic","methodology":"Counts foreign-trained doctors and nurses in OECD destination countries by country of training, from national registers and censuses.","limitations":"Coverage is destination = OECD only (South-South flows missing), measures stock of professionals present rather than recruitment flow, and corridors drawn between centroids are indicative.","confidence":"medium"},"migration":{"label":"Migration corridors","metric":"Origin-to-destination stock of international migrants (foreign-born persons residing in each country).","unit":"category / count of migrants","higherIs":"neutral","colorMeaning":"Path color/weight encodes the size of the migrant stock along each origin\u2013destination corridor.","primarySource":{"org":"UN DESA Population Division","datasetTitle":"International Migrant Stock 2024","url":"https://www.un.org/development/desa/pd/content/international-migrant-stock","year":"2024"},"additionalSources":[{"org":"World Bank","datasetTitle":"Global Bilateral Migration Database","url":"https://databank.worldbank.org/source/global-bilateral-migration"}],"dataKind":"estimated","provenance":"primary","updateFrequency":"periodic","methodology":"Estimates foreign-born persons residing in each country by origin and destination, built mainly from population censuses and registers.","limitations":"A stock snapshot of where migrants live, not a flow, so drawing origin\u2013destination as a moving path is an interpolation; the World Bank bilateral matrix ends at 2000.","confidence":"medium"},"trade":{"label":"Trade flows","metric":"Bilateral merchandise trade (imports/exports) between countries.","unit":"category / USD value","higherIs":"neutral","colorMeaning":"Path color/weight encodes the value of merchandise trade along each bilateral corridor.","primarySource":{"org":"UN Statistics Division","datasetTitle":"UN Comtrade Database","url":"https://comtradeplus.un.org/","year":"2024"},"additionalSources":[{"org":"OECD / WTO","datasetTitle":"Balanced International Merchandise Trade Statistics (BIMTS)","url":"https://www.oecd.org/en/data/datasets/oecd-balanced-trade-statistics.html"}],"dataKind":"measured","provenance":"primary","updateFrequency":"continuous/rolling (annual + monthly)","methodology":"Compiles official bilateral import/export merchandise statistics reported by national statistical authorities, by partner and commodity.","limitations":"Reporting lags and gaps leave some recent partners incomplete, and importer- vs. exporter-reported figures for the same corridor often differ (mirror asymmetry).","confidence":"high"},"cables":{"label":"Submarine cables","metric":"Routes of submarine communications cable systems and their landing points.","unit":"category / cable system","higherIs":"neutral","colorMeaning":"Lines depict individual submarine cable systems (color distinguishes systems, not magnitude).","primarySource":{"org":"TeleGeography","datasetTitle":"Submarine Cable Map","url":"https://www.submarinecablemap.com/","year":"2025"},"additionalSources":[{"org":"TeleGeography","datasetTitle":"Submarine Cable Map 2025 (print edition)","url":"https://submarine-cable-map-2025.telegeography.com/"}],"dataKind":"curated","provenance":"primary","updateFrequency":"rolling (interactive); annual (print)","methodology":"Cable systems, landing stations, ownership, length, and service dates compiled from operator filings and industry research.","limitations":"Routes are schematic/stylized representations, not exact geodetic cable paths, and the free dataset lacks precise geocoded geometry.","confidence":"high"},"drugs":{"label":"Drug routes","metric":"Indicative international trafficking corridors for illicit drugs.","unit":"category / indicative corridor","higherIs":"bad","colorMeaning":"Path color encodes drug type or trafficking corridor; weight is indicative of relative flow.","primarySource":{"org":"UN Office on Drugs and Crime","datasetTitle":"World Drug Report 2025","url":"https://www.unodc.org/unodc/en/data-and-analysis/world-drug-report-2025.html","year":"2025"},"additionalSources":[{"org":"UNODC","datasetTitle":"World Drug Report 2025 maps","url":"https://www.unodc.org/unodc/en/data-and-analysis/world-drug-report-2025-maps.html"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"annual","methodology":"Routes are inferred from seizure data and Member States' reported countries of departure, transit, and destination, aggregated into broadly indicative corridors.","limitations":"UNODC states routes are broadly indicative only; corridors are country-pair inferences drawn between centroids, not tracked geodata, and secondary routes may be missing.","confidence":"low"},"arms":{"label":"Arms trafficking","metric":"Transfers of conventional arms and small arms between supplier and recipient countries, including illicit diversion.","unit":"category / transfer value (TIV)","higherIs":"bad","colorMeaning":"Path color/weight encodes the volume or value of arms transferred along supplier\u2013recipient corridors.","primarySource":{"org":"SIPRI","datasetTitle":"Arms Transfers Database / Trends in International Arms Transfers 2025","url":"https://www.sipri.org/databases/armstransfers","year":"2025 (updated March 2026)"},"additionalSources":[{"org":"Small Arms Survey","datasetTitle":"Annual Report 2024 / small arms trade updates","url":"https://www.smallarmssurvey.org/"},{"org":"UNODC","datasetTitle":"Global Study on Firearms Trafficking","url":"https://www.unodc.org/unodc/en/firearms-protocol/firearms-study.html"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"annual","methodology":"SIPRI tracks deliveries of major conventional arms by supplier/recipient as trend-indicator values; Small Arms Survey models authorized small-arms trade and overlays illicit-diversion research.","limitations":"SIPRI covers legal major-arms transfers only (real flow pairs), while illicit small-arms corridors are estimated and partial because diversion is by definition under-reported.","confidence":"medium"},"trafficking":{"label":"Human trafficking","metric":"Cross-border origin-to-destination flows of detected trafficking victims.","unit":"category / indicative flow","higherIs":"bad","colorMeaning":"Path color/weight encodes the origin\u2013destination flow of detected trafficking victims.","primarySource":{"org":"UN Office on Drugs and Crime","datasetTitle":"Global Report on Trafficking in Persons 2024","url":"https://www.unodc.org/unodc/en/data-and-analysis/glotip.html","year":"2024"},"additionalSources":[{"org":"UNODC","datasetTitle":"GLOTIP 2024 report (PDF)","url":"https://www.unodc.org/documents/data-and-analysis/glotip/2024/GLOTIP2024_BOOK.pdf"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"periodic (roughly biennial)","methodology":"Cross-border flows derived from detected-victim citizenship vs. country of detection, aggregated into origin\u2013destination region pairs.","limitations":"Reflects only detected victims and is heavily shaped by national detection capacity, so flows show where victims are found, not true scale or all routes.","confidence":"low"},"wildlife":{"label":"Wildlife trafficking","metric":"Indicative trafficking corridors for illegally traded wildlife and wildlife products.","unit":"category / indicative corridor","higherIs":"bad","colorMeaning":"Path color/weight encodes indicative wildlife trafficking corridors between source and destination regions.","primarySource":{"org":"UN Office on Drugs and Crime (for the CITES Secretariat)","datasetTitle":"World Wildlife Crime Report 2024","url":"https://www.unodc.org/unodc/en/data-and-analysis/wildlife.html","year":"2024 (seizure data 2015\u20132021)"},"additionalSources":[{"org":"CITES Secretariat","datasetTitle":"CITES Illegal Trade Database","url":"https://cites.org/"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"periodic (roughly every four years)","methodology":"Trafficking patterns built from national annual illegal-trade (seizure) reports submitted by CITES Parties.","limitations":"Seizure-based, so it maps interdiction points and reporting effort; successful (un-seized) flows and non-reporting countries are invisible.","confidence":"low"},"counterfeit":{"label":"Counterfeit goods","metric":"Estimated provenance and transit corridors of counterfeit and IP-infringing goods in world trade.","unit":"category / estimated value share","higherIs":"bad","colorMeaning":"Path color/weight encodes estimated provenance/transit volume of counterfeit goods.","primarySource":{"org":"OECD & EUIPO","datasetTitle":"Mapping Global Trade in Fakes 2025","url":"https://www.oecd.org/en/publications/mapping-global-trade-in-fakes-2025_94d3b29f-en.html","year":"2025 (reference year 2021)"},"additionalSources":[{"org":"OECD","datasetTitle":"Global Trade in Fakes 2025 (PDF)","url":"https://www.oecd.org/content/dam/oecd/en/publications/reports/2025/05/mapping-global-trade-in-fakes-2025_5c812e3c/94d3b29f-en.pdf"}],"dataKind":"modeled","provenance":"synthesized","updateFrequency":"periodic (roughly every three years)","methodology":"Provenance/transit corridors estimated from global customs seizure data (GTRIC index) combined with bilateral trade statistics.","limitations":"Based on seizures (biased toward well-enforced borders) with a multi-year lag, and provenance often shows transit hubs rather than true origin.","confidence":"low"},"currents":{"label":"Ocean currents","metric":"Direction and speed of near-surface ocean currents.","unit":"category / m per s","higherIs":"neutral","colorMeaning":"Lines/arrows encode current direction; color or weight may encode speed.","primarySource":{"org":"NASA JPL PO.DAAC","datasetTitle":"OSCAR Surface Currents 0.25\u00b0 Version 2.0","url":"https://podaac.jpl.nasa.gov/dataset/OSCAR_L4_OC_FINAL_V2.0","year":"ongoing (v2.0 since 2022)"},"additionalSources":[{"org":"NOAA AOML","datasetTitle":"Global Drifter Program surface current climatology","url":"https://www.aoml.noaa.gov/global-drifter-program/"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"daily (rolling)","methodology":"OSCAR diagnoses near-surface currents from satellite sea-surface height, vector winds, and SST via a geostrophic/Ekman model; drifters measure currents directly.","limitations":"OSCAR is a 0.25\u00b0 model-derived product that smooths fine-scale and coastal features and represents only the surface mixed layer, not deep or instantaneous flow.","confidence":"high"},"flyways":{"label":"Bird migration flyways","metric":"Generalized broad corridors used by migratory bird populations.","unit":"category / flyway zone","higherIs":"neutral","colorMeaning":"Color distinguishes the major flyway zones (color encodes category, not magnitude).","primarySource":{"org":"BirdLife International","datasetTitle":"Global Flyways / DataZone migratory-bird profiles","url":"https://www.birdlife.org/globalflyways/","year":"2025"},"additionalSources":[{"org":"East Asian-Australasian Flyway Partnership","datasetTitle":"Flyway Site Network","url":"https://eaaflyway.net/the-flyway/flyway-site-network/"},{"org":"Convention on Migratory Species (CMS)","datasetTitle":"CMS flyway framework","url":"https://www.cms.int/"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"periodic","methodology":"Flyway boundaries are expert-delineated generalized zones synthesizing ringing/recovery, tracking, and species-distribution data.","limitations":"Flyways are conceptual broad corridors and conservation constructs, not precise per-species paths; boundaries are smoothed and schematic.","confidence":"medium"},"dust":{"label":"Saharan dust","metric":"Seasonal/episodic atmospheric transport of Saharan mineral dust.","unit":"category / aerosol optical depth","higherIs":"neutral","colorMeaning":"Path/shading encodes the direction and intensity of dust plume transport.","primarySource":{"org":"NASA (Goddard / Earth Observatory)","datasetTitle":"GEOS-FP aerosol product (dust AOT) with MODIS AOD and CALIPSO profiles","url":"https://svs.gsfc.nasa.gov/5572/","year":"ongoing (near-real-time)"},"additionalSources":[{"org":"NASA Earth Observatory","datasetTitle":"Earth Observatory dust imagery / Worldview","url":"https://science.nasa.gov/earth/earth-observatory/"}],"dataKind":"modeled","provenance":"synthesized","updateFrequency":"daily (near-real-time); episodic phenomenon","methodology":"Dust transport modeled by the GEOS aerosol system assimilating MODIS AOD and other satellite data, with CALIPSO lidar providing vertical structure.","limitations":"No single 'dust route' dataset exists; this layer is synthesized from model and multi-sensor imagery, and plume paths are episodic and seasonal rather than fixed corridors.","confidence":"medium"},"silkroad":{"label":"Silk Road","metric":"Reconstructed historical routes of the Silk Road exchange networks.","unit":"category / historical route","higherIs":"neutral","colorMeaning":"Lines depict reconstructed historical trade routes (color distinguishes branches, not magnitude).","primarySource":{"org":"UNESCO","datasetTitle":"Silk Roads Programme \u2014 Interactive Map / Online Platform","url":"https://en.unesco.org/silkroad/","year":"ongoing/curated"},"additionalSources":[{"org":"UNESCO World Heritage Centre","datasetTitle":"Silk Roads corridor inscriptions (Chang'an-Tianshan 2014; Zarafshan-Karakum 2023)","url":"https://whc.unesco.org/en/list/1442/"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"static/historical","methodology":"Routes are scholarly reconstructions of historical exchange networks compiled by UNESCO and partner historians.","limitations":"Interpretive historical corridors that are approximate, contested, and stylized; UNESCO's authoritative route geometry (Interactive Atlas) is still in development.","confidence":"medium"},"voyages":{"label":"Age of Exploration","metric":"Reconstructed maritime routes of Age-of-Exploration and transatlantic slave-trade voyages.","unit":"category / historical voyage","higherIs":"neutral","colorMeaning":"Lines depict reconstructed historical voyage routes (color distinguishes era/trade, not magnitude).","primarySource":{"org":"SlaveVoyages (Rice University / Hutchins Center, Harvard)","datasetTitle":"Trans-Atlantic Slave Trade Database","url":"https://www.slavevoyages.org/","year":"1514\u20131866 (periodically updated)"},"additionalSources":[{"org":"SlaveVoyages","datasetTitle":"Intra-American Slave Trade Database","url":"https://www.slavevoyages.org/voyages/about"}],"dataKind":"curated","provenance":"synthesized","updateFrequency":"periodic (as archival evidence surfaces)","methodology":"Each voyage is reconstructed from archival shipping and customs records, with routes inferred from documented embarkation and disembarkation points.","limitations":"Routes are point-to-point reconstructions from incomplete records (not actual sailed tracks); Age-of-Exploration explorer routes have no canonical open dataset and must be curated separately.","confidence":"medium"},"flights":{"label":"Flight corridors","metric":"Scheduled air routes between airport pairs / air traffic corridors.","unit":"category / route","higherIs":"neutral","colorMeaning":"Lines depict airport-pair routes; weight may encode relative traffic.","primarySource":{"org":"OpenFlights","datasetTitle":"Airport, Airline and Route Database","url":"https://openflights.org/data.php","year":"routes frozen 2014; infrastructure updated 2025"},"additionalSources":[{"org":"Eurocontrol","datasetTitle":"Our Data / Aviation Data Repository","url":"https://www.eurocontrol.int/our-data"}],"dataKind":"curated","provenance":"secondary","updateFrequency":"static (OpenFlights routes); monthly (Eurocontrol)","methodology":"OpenFlights routes are straight-line airport-pair connections crowdsourced from a third-party feed; Eurocontrol derives flows from filed flight plans and radar tracks.","limitations":"OpenFlights route data is frozen at June 2014 and is of historical value only; lines are great-circle approximations, not actual flown tracks (OAG/ICAO are paywalled).","confidence":"medium"},"shipping":{"label":"Shipping lanes","metric":"Maritime traffic density along major shipping lanes and through chokepoints.","unit":"category / transit volume","higherIs":"neutral","colorMeaning":"Path color/weight encodes maritime traffic density or transit volume.","primarySource":{"org":"IMF","datasetTitle":"PortWatch (Ports & Chokepoints datasets)","url":"https://portwatch.imf.org/","year":"ongoing (AIS daily since 2019)"},"additionalSources":[{"org":"UNCTAD","datasetTitle":"Review of Maritime Transport 2025","url":"https://unctad.org/publication/review-maritime-transport-2025"}],"dataKind":"modeled","provenance":"primary","updateFrequency":"daily/weekly (PortWatch); annual (UNCTAD)","methodology":"PortWatch estimates trade flows from satellite AIS signals on ~90,000 ships processed with big-data/ML models; UNCTAD aggregates national seaborne-trade statistics.","limitations":"AIS is subject to jamming, spoofing, and vessels going dark, and downloadable density layers are derived estimates, not raw tracks (MarineTraffic is commercial).","confidence":"high"},"refugees":{"label":"Refugee flows","metric":"Refugee and asylum-seeker populations by country of origin and country of asylum.","unit":"category / count of persons","higherIs":"context","colorMeaning":"Path color/weight encodes the size of the refugee population along each origin\u2013asylum corridor.","primarySource":{"org":"UNHCR","datasetTitle":"Refugee Data Finder (Population Statistics Database)","url":"https://www.unhcr.org/refugee-statistics","year":"end-2024"},"additionalSources":[{"org":"UNHCR","datasetTitle":"Global Trends report","url":"https://www.unhcr.org/global-trends"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual (mid-year + year-end)","methodology":"Compiles refugee, asylum-seeker, IDP, and stateless populations by origin and asylum country from government and UNHCR registration/reporting.","limitations":"Reflects registered/recognized populations residing in host countries (an origin\u2013asylum pairing), not real-time crossing flows; unregistered populations are undercounted.","confidence":"high"},"students":{"label":"International students","metric":"Tertiary students enrolled outside their country of origin, by origin and destination.","unit":"category / count of students","higherIs":"neutral","colorMeaning":"Path color/weight encodes the number of mobile students along each origin\u2013destination corridor.","primarySource":{"org":"UNESCO Institute for Statistics","datasetTitle":"Inbound/Outbound Internationally Mobile Students","url":"https://databrowser.uis.unesco.org/browser/EDUCATION/UIS-EducationOPRI/int-stud","year":"2022"},"additionalSources":[{"org":"Institute of International Education","datasetTitle":"Project Atlas (2024 release)","url":"https://www.iie.org/research-initiatives/project-atlas/"},{"org":"OECD","datasetTitle":"International Migration Outlook / Education at a Glance","url":"https://www.oecd.org/en/topics/education.html"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual","methodology":"Counts tertiary students enrolled outside their country of origin, by destination and origin region/country, reported by national authorities.","limitations":"Origin detail is incomplete (often only by region for inbound), and definitions of 'mobile' vary by country, so some corridors are partial.","confidence":"high"},"remit":{"label":"Remittance corridors","metric":"Estimated bilateral remittance transfers from host countries to origin countries.","unit":"category / USD value","higherIs":"good","colorMeaning":"Path color/weight encodes the estimated value of remittances along each corridor.","primarySource":{"org":"World Bank / KNOMAD","datasetTitle":"Bilateral Remittance Matrix","url":"https://data360.worldbank.org/en/indicator/WB_KNOMAD_BRE","year":"2024"},"additionalSources":[{"org":"KNOMAD","datasetTitle":"Remittances data","url":"https://www.knomad.org/data/remittances"}],"dataKind":"modeled","provenance":"synthesized","updateFrequency":"annual","methodology":"Allocates each country's measured total remittance inflows across source countries in proportion to migrant stocks and per-capita incomes of host vs. origin.","limitations":"The bilateral corridor cells are modeled, not measured \u2014 only country-level totals are real, and informal/unrecorded transfers are excluded.","confidence":"medium"},"debtout":{"label":"Bilateral debt (creditor side)","metric":"Money lent out: external debt owed to each creditor country by low- and middle-income borrowers.","unit":"category / USD value","higherIs":"context","colorMeaning":"Path color/weight encodes the amount lent out from each creditor country to debtor countries.","primarySource":{"org":"World Bank","datasetTitle":"International Debt Statistics (IDS) / International Debt Report 2025","url":"https://www.worldbank.org/en/programs/debt-statistics","year":"end-2024"},"additionalSources":[{"org":"World Bank","datasetTitle":"International Debt Report 2025 products","url":"https://www.worldbank.org/en/programs/debt-statistics/idr/products"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual (database refreshed quarterly)","methodology":"Compiles external debt stocks and flows of low- and middle-income countries via the Debtor Reporting System, broken out by creditor type and increasingly by creditor country.","limitations":"Debtor-reported and limited to LMIC borrowers, so the creditor side is partial \u2014 lending among high-income countries and some non-Paris-Club/Chinese lending is inconsistently attributed.","confidence":"medium"},"debtin":{"label":"Bilateral debt (debtor side)","metric":"Money owed: external debt that each low- and middle-income borrower owes to bilateral creditors.","unit":"category / USD value","higherIs":"context","colorMeaning":"Path color/weight encodes the amount each debtor country owes to creditor countries.","primarySource":{"org":"World Bank","datasetTitle":"International Debt Statistics (IDS) / International Debt Report 2025","url":"https://www.worldbank.org/en/programs/debt-statistics","year":"end-2024"},"additionalSources":[{"org":"World Bank","datasetTitle":"International Debt Report 2025 products","url":"https://www.worldbank.org/en/programs/debt-statistics/idr/products"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual (database refreshed quarterly)","methodology":"Compiles the external debt obligations of low- and middle-income borrowers reported via the Debtor Reporting System, broken out by creditor.","limitations":"Coverage is debtor-reported and limited to LMIC borrowers; high-income borrowers are excluded and some creditor attribution is incomplete.","confidence":"medium"},"oil":{"label":"Oil & gas trade","metric":"Inter-regional and bilateral trade movements of crude oil, refined products, and natural gas.","unit":"category / volume or value","higherIs":"neutral","colorMeaning":"Path color/weight encodes the volume of oil/gas traded along each corridor.","primarySource":{"org":"Energy Institute","datasetTitle":"Statistical Review of World Energy 2025 (74th edition)","url":"https://www.energyinst.org/statistical-review","year":"2025 (data for 2024)"},"additionalSources":[{"org":"UN Statistics Division","datasetTitle":"UN Comtrade Database","url":"https://comtradeplus.un.org/"},{"org":"International Energy Agency","datasetTitle":"Oil/Gas market data","url":"https://www.iea.org/data-and-statistics"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual","methodology":"Compiles national/industry production, consumption, and inter-regional trade-movement matrices (origin region \u2192 destination region).","limitations":"Trade-movement tables are inter-regional aggregates, not country-to-country pipeline/tanker geometry; granular bilateral flows require UN Comtrade or IEA.","confidence":"high"},"food":{"label":"Food & grain trade","metric":"Bilateral import/export quantities and values of food and agricultural commodities.","unit":"category / quantity or value","higherIs":"neutral","colorMeaning":"Path color/weight encodes the volume of food/grain traded along each corridor.","primarySource":{"org":"FAO","datasetTitle":"FAOSTAT \u2014 Detailed trade matrix (crops and livestock products)","url":"https://www.fao.org/faostat/en/#data/TM","year":"2025 update (through ~2023/2024)"},"additionalSources":[{"org":"UN Statistics Division","datasetTitle":"UN Comtrade Database","url":"https://comtradeplus.un.org/"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual","methodology":"Bilateral (reporter\u2194partner) import/export quantities and values by commodity, harmonized largely from UN Comtrade and national submissions.","limitations":"A one-to-two-year reporting lag and mirror-statistics discrepancies (reporter vs. partner figures often disagree).","confidence":"high"},"minerals":{"label":"Minerals & metals trade","metric":"World production, reserves, and trade/source flows of mineral commodities and metals.","unit":"category / quantity or value","higherIs":"neutral","colorMeaning":"Path color/weight encodes the volume of minerals/metals traded or sourced along each corridor.","primarySource":{"org":"U.S. Geological Survey","datasetTitle":"Mineral Commodity Summaries 2026","url":"https://pubs.usgs.gov/publication/mcs2026","year":"2026 (data for 2025)"},"additionalSources":[{"org":"UN Statistics Division","datasetTitle":"UN Comtrade Database","url":"https://comtradeplus.un.org/"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual","methodology":"Reports per-commodity world production and reserves plus US net import reliance and major source countries.","limitations":"US-centric \u2014 gives global production and US import sources, not full bilateral world flow matrices; country-to-country flows require UN Comtrade.","confidence":"high"},"wood":{"label":"Timber & wood trade","metric":"Production and trade quantities/values of wood and paper products (roundwood, sawnwood, panels, pulp, paper).","unit":"category / quantity or value","higherIs":"neutral","colorMeaning":"Path color/weight encodes the volume of timber/wood traded along each corridor.","primarySource":{"org":"FAO","datasetTitle":"FAOSTAT \u2014 Forestry Production and Trade","url":"https://www.fao.org/faostat/en/#data/FO","year":"2025 update (through 2024)"},"additionalSources":[{"org":"UN Statistics Division","datasetTitle":"UN Comtrade Database","url":"https://comtradeplus.un.org/"}],"dataKind":"measured","provenance":"primary","updateFrequency":"annual","methodology":"Annual production and trade quantities/values for wood and paper products, collected via the joint FAO/ITTO/Eurostat/UNECE questionnaire.","limitations":"Headline domain is production plus aggregate trade by country, not full bilateral matrices, and excludes illegal/unrecorded logging; partner-level flows need the trade matrix or Comtrade.","confidence":"high"},"_borders":{"label":"Borders & territory provenance","description":"How the map renders sovereign borders and handles disputed sovereignty.","default_policy":{"policy":"Internationally recognized borders by default; disputed control shown as metadata where available, not silently resolved.","note":"Renders the de facto controlled boundary by default and carries de jure claim lines and point-of-view variants as separate metadata layers, consistent with Natural Earth's disputed-boundaries convention and the UN member-state list (193 members + 2 observer states).","source":"https://www.naturalearthdata.com/about/disputed-boundaries-policy/"},"taiwan":{"policy":"Show Taiwan (Republic of China) as a de facto self-governing entity with its own ISO 3166-1 code (TW), flagging the PRC's claim and Taiwan's lack of a UN seat as metadata.","note":"The PRC holds the China seat at the UN (GA Resolution 2758, 1971) and Taiwan is not a UN member; ISO 3166 lists it as 'Taiwan, Province of China' (TW). As of 2025 the ROC retains formal diplomatic relations with about 12 states.","source":"https://en.wikipedia.org/wiki/International_recognition_of_Taiwan"},"crimea_ukraine":{"policy":"Render Crimea as internationally recognized Ukrainian territory under Russian de facto occupation, noting the occupation as metadata rather than a sovereignty transfer.","note":"Russia annexed Crimea in March 2014 after a referendum the UN declared invalid; UN General Assembly Resolution 68/262 (27 March 2014) affirmed Ukraine's internationally recognized borders, and non-recognition of the annexation remains the prevailing position.","source":"https://docs.un.org/A/Res/68/262"},"kosovo":{"policy":"Treat Kosovo as a partially recognized de facto state (independence declared 2008), explicitly flagging that recognition is contested and Serbia does not recognize it.","note":"As of late 2025 roughly 110 of 193 UN members recognize Kosovo (Belgrade cites a lower figure after withdrawals); Kosovo is not a UN member, and 5 EU states plus Serbia withhold recognition. It has no official ISO 3166-1 code and uses the placeholder XK.","source":"https://en.wikipedia.org/wiki/International_recognition_of_Kosovo"},"israel_palestine":{"policy":"Show Israel as a recognized sovereign state and the State of Palestine (West Bank including East Jerusalem, and Gaza) as a partially recognized UN non-member observer state, with borders, settlements, and East Jerusalem's status carried as disputed metadata.","note":"Palestine has been a UN non-member observer state since November 2012 (rights expanded by Resolution ES-10/23 in May 2024); as of September 2025 it is recognized by about 157 of 193 UN members, including a 2025 wave of recognitions led by France, Canada, and the UK.","source":"https://en.wikipedia.org/wiki/International_recognition_of_the_State_of_Palestine"},"western_sahara":{"policy":"Mark Western Sahara as a UN-listed Non-Self-Governing Territory with no internationally recognized sovereign, showing Moroccan de facto control and SADR/Polisario control as disputed metadata rather than settled sovereignty.","note":"A UN Non-Self-Governing Territory since 1963 with self-determination still pending; MINURSO's mandate was renewed on 31 October 2025, and a US-sponsored Security Council resolution that month endorsed Morocco's autonomy plan as a basis for negotiations, while Polisario (backed by Algeria) continues to demand a referendum.","source":"https://www.un.org/dppa/decolonization/en/nsgt/western-sahara"}}};
function provKeyFor(k){ return k.indexOf("flow_")===0 ? k.slice(5) : k; }
function _confCol(c){ return ({high:"#5bd6c0",medium:"#f2b84b",low:"#e0683f"})[c]||"#9fb0c4"; }
function _higherTxt(h){ return ({good:"higher = better",bad:"higher = worse",context:"higher = context-dependent",neutral:""})[h]||""; }
function _provBadge(txt,col){ if(!txt) return ""; return `<span style="display:inline-block;font-size:9px;text-transform:uppercase;letter-spacing:.4px;color:${col};border:1px solid ${col}55;border-radius:4px;padding:1px 5px;margin:0 4px 4px 0">${txt}</span>`; }
function _provSrc(s){ if(!s||!s.url) return ""; const t=[s.org,s.datasetTitle].filter(Boolean).join(" \u2014 ")+(s.year?(" ("+s.year+")"):""); return `<a href="${s.url}" target="_blank" rel="noopener">\u2197 ${escapeHTML(t)}</a>`; }
function provCard(key){
  const pv=LAYER_PROV[provKeyFor(key)]; if(!pv) return "";
  let h=`<div style="border:1px solid var(--line);border-radius:10px;padding:11px 12px;margin-bottom:9px">`;
  h+=`<div style="font-size:13px;font-weight:650;color:#e8eef6">${escapeHTML(pv.label||"")}</div>`;
  if(pv.metric) h+=`<div style="font-size:11.5px;color:var(--muted);margin-top:2px;line-height:1.4">${escapeHTML(pv.metric)}</div>`;
  let meta=[]; if(pv.unit) meta.push("Unit: "+escapeHTML(pv.unit)); if(pv.colorMeaning) meta.push("Color: "+escapeHTML(pv.colorMeaning)); if(pv.updateFrequency) meta.push("Updates: "+escapeHTML(pv.updateFrequency));
  if(meta.length) h+=`<div style="font-size:10.5px;color:#8a97a8;margin-top:5px;line-height:1.45">${meta.join(" &middot; ")}</div>`;
  h+=`<div style="margin-top:7px;line-height:1.9">`+_provBadge((pv.confidence||"")+" confidence",_confCol(pv.confidence))+_provBadge(pv.dataKind,"#9fb0c4")+_provBadge(pv.provenance,"#9fb0c4")+_provBadge(_higherTxt(pv.higherIs),"#9fb0c4")+`</div>`;
  const src=_provSrc(pv.primarySource)+(pv.additionalSources||[]).map(_provSrc).join("");
  if(src) h+=`<div class="src" style="margin-top:6px">`+src+`</div>`;
  if(pv.methodology) h+=`<div style="font-size:10.5px;color:#8a97a8;margin-top:6px;line-height:1.45"><b style="color:#9fb0c4">Method:</b> ${escapeHTML(pv.methodology)}</div>`;
  if(pv.limitations) h+=`<div style="font-size:10.5px;color:#8a97a8;margin-top:3px;line-height:1.45"><b style="color:#9fb0c4">Limitations:</b> ${escapeHTML(pv.limitations)}</div>`;
  return h+`</div>`;
}
function buildSourcesIndex(){
  let out="", order=[], seen={};
  META.layers.forEach(l=>{ if(!seen[l.group]){ seen[l.group]=[]; order.push(l.group); } seen[l.group].push(l); });
  out+=`<div style="font-size:11.5px;color:var(--muted);margin:-2px 0 14px;line-height:1.5">Every layer below lists what it measures, its unit, what the color means, the issuing source, the method, limitations, and a confidence rating. Data is bundled at load \u2014 nothing is fetched on hover.</div>`;
  order.forEach(g=>{ const cards=seen[g].map(l=>provCard(l.key)).filter(Boolean).join(""); if(cards) out+=`<div class="sec"><h4>${escapeHTML(g)}</h4>${cards}</div>`; });
  const b=LAYER_PROV._borders;
  if(b){
    out+=`<div class="sec"><h4>${escapeHTML(b.label||"Borders & disputed territories")}</h4>`;
    if(b.description) out+=`<div style="font-size:11.5px;color:var(--muted);margin-bottom:9px;line-height:1.45">${escapeHTML(b.description)}</div>`;
    ["default_policy","taiwan","crimea_ukraine","kosovo","israel_palestine","western_sahara"].forEach(k=>{ const e=b[k]; if(!e) return;
      out+=`<div style="border:1px solid var(--line);border-radius:10px;padding:9px 11px;margin-bottom:8px">`;
      out+=`<div style="font-size:12px;font-weight:600;color:#e8eef6;text-transform:capitalize">${escapeHTML(e.label||k.replace(/_/g," "))}</div>`;
      if(e.policy) out+=`<div style="font-size:10.5px;color:#8a97a8;margin-top:3px;line-height:1.45">${escapeHTML(e.policy)}</div>`;
      if(e.note) out+=`<div style="font-size:10.5px;color:#8a97a8;margin-top:3px;line-height:1.45">${escapeHTML(e.note)}</div>`;
      const su=(typeof e.source==="string")?e.source:(e.source&&e.source.url); if(su) out+=`<div class="src" style="margin-top:4px"><a href="${su}" target="_blank" rel="noopener">\u2197 source</a></div>`;
      out+=`</div>`;
    });
    out+=`</div>`;
  }
  return out;
}
/* ===== end sources & methodology =========================================== */'''
OLD_FN=r'''function buildSourcesIndex(){
  const groups={};
  allSources().forEach(s=>{ const p=publisherFor(s); (groups[p]=groups[p]||[]).push(s); });
  return Object.keys(groups).sort((a,b)=>a.localeCompare(b)).map(p=>{
    const links=groups[p].sort((a,b)=>sourceLabel(a).localeCompare(sourceLabel(b))).map(sourceLink).join("");
    return `<div class="sec"><h4>${escapeHTML(p)}</h4><div class="src">${links}</div></div>`;
  }).join("");
}'''
HDR_OLD=r'''  document.getElementById("pName").textContent="Sources";
  document.getElementById("pMaj").textContent=`${allSources().length} cited datasets, reports, and services`;'''
HDR_NEW=r'''  document.getElementById("pName").textContent="Sources & Methodology";
  document.getElementById("pMaj").textContent=`Provenance for every layer \u2014 source, method, limitations, confidence`;'''
res=[]
if "const LAYER_PROV=" in text: res.append("already-applied")
elif OLD_FN in text: text=text.replace(OLD_FN, NEW, 1); res.append("replaced buildSourcesIndex")
else: res.append("ANCHOR-NOT-FOUND(buildSourcesIndex)")
if HDR_OLD in text: text=text.replace(HDR_OLD, HDR_NEW, 1); res.append("header updated")
elif 'textContent="Sources & Methodology"' in text: res.append("header already")
else: res.append("header anchor missing")
open(OUT,"w",encoding="utf-8").write(text)
